def verify(answer):
    import re
    from math import isclose

    # Try to extract a numeric value from the answer string
    answer_str = str(answer).strip()

    # Try direct numeric parsing
    try:
        val = float(answer_str)
        return isclose(val, 4.0, rel_tol=1e-6)
    except ValueError:
        pass

    # Try to handle expressions like "4", "4.0", "2+2", etc.
    # Remove common formatting
    cleaned = answer_str.replace(',', '.').strip()

    # Try eval with math functions
    import math
    try:
        val = eval(cleaned, {"__builtins__": {}}, 
                   {"sqrt": math.sqrt, "pi": math.pi, "e": math.e})
        return isclose(float(val), 4.0, rel_tol=1e-6)
    except:
        pass

    # Try sympy parsing
    try:
        import sympy as sp
        expr = sp.sympify(answer_str)
        val = float(expr.evalf())
        return isclose(val, 4.0, rel_tol=1e-6)
    except:
        pass

    # Check for string representations of 4
    if answer_str in ["4", "4.0", "four"]:
        return True

    return False

def verify(answer):
    import re
    from fractions import Fraction

    # Try to parse the answer as a rational number
    answer = answer.strip()

    # Try to extract a number
    # Handle fractions like p/q
    try:
        # Try direct fraction parsing
        if '/' in answer:
            parts = answer.split('/')
            if len(parts) == 2:
                num = int(parts[0].strip())
                den = int(parts[1].strip())
                candidate = Fraction(num, den)
            else:
                return False
        else:
            # Try integer or float
            candidate = Fraction(answer)
    except:
        # Try to find a number in the string
        try:
            numbers = re.findall(r'-?\d+(?:/\d+)?', answer)
            if numbers:
                candidate = Fraction(numbers[0])
            else:
                return False
        except:
            return False

    # Compute the partial sum numerically to verify
    target = Fraction(2, 1)  # We computed the sum = 2

    # Also verify numerically
    s = 0.0
    for k in range(1, 100):
        s += (6**k) / ((3**(k+1) - 2**(k+1)) * (3**k - 2**k))

    # Check if candidate matches both our analytical result and numerical computation
    candidate_float = float(candidate)

    if abs(candidate_float - s) < 1e-6 and candidate == target:
        return True

    # Maybe just check numerical closeness if exact form differs
    if abs(candidate_float - s) < 1e-6:
        return True

    return False

def verify(answer):
    import sympy as sp
    import random

    # Define symbols
    a, b, n_sym = sp.symbols('a b n')

    def make_matrix(n_val, x_val, a_val, b_val):
        size = 2 * n_val
        M = []
        for i in range(1, size + 1):
            row = []
            for j in range(1, size + 1):
                if i == j:
                    row.append(x_val)
                elif (i + j) % 2 == 0:
                    row.append(a_val)
                else:
                    row.append(b_val)
            M.append(row)
        return sp.Matrix(M)

    # Compute the limit for specific n values symbolically
    x = sp.Symbol('x')
    a_s, b_s = sp.symbols('a b')

    computed_values = {}
    for n_val in [1, 2, 3]:
        M = make_matrix(n_val, x, a_s, b_s)
        det = M.det()
        # The limit of det/(x-a)^(2n-2) as x->a
        power = 2 * n_val - 2
        # Compute limit
        expr = det / (x - a_s)**power
        lim = sp.limit(expr, x, a_s)
        lim_simplified = sp.simplify(sp.expand(lim))
        computed_values[n_val] = lim_simplified

    # Now try to parse the answer and check against computed values
    # The answer should be a polynomial in a, b, n
    # Try to evaluate the candidate answer at specific (a, b, n) values

    # Parse the answer string as a sympy expression
    n_sym2 = sp.Symbol('n')
    try:
        candidate = sp.sympify(answer, locals={'a': a_s, 'b': b_s, 'n': n_sym2})
    except:
        return False

    # Check for n=1,2,3
    random.seed(42)
    test_cases = []
    for n_val in [1, 2, 3]:
        # Use specific a,b values
        for _ in range(3):
            a_val = random.uniform(-2, 2)
            b_val = random.uniform(-2, 2)
            while abs(a_val - b_val) < 0.1:
                b_val = random.uniform(-2, 2)
            test_cases.append((n_val, a_val, b_val))

    for n_val, a_val, b_val in test_cases:
        # Compute ground truth
        computed = computed_values[n_val].subs([(a_s, a_val), (b_s, b_val)])
        computed_float = float(computed.evalf())

        # Evaluate candidate
        try:
            cand_val = candidate.subs([(a_s, a_val), (b_s, b_val), (n_sym2, n_val)])
            cand_float = float(cand_val.evalf())
        except:
            return False

        if abs(computed_float) < 1e-10:
            if abs(cand_float) > 1e-6:
                return False
        else:
            if abs((computed_float - cand_float) / computed_float) > 1e-4:
                return False

    return True

