def verify(answer):
    # First compute the actual answer
    def d(n):
        return bin(n).count('1')

    S = 0
    for k in range(1, 2021):
        S += ((-1) ** d(k)) * (k ** 3)

    S_mod = S % 2020

    # Parse the answer
    try:
        candidate = int(str(answer).strip())
        return candidate % 2020 == S_mod
    except:
        # Try to extract a number
        import re
        nums = re.findall(r'-?\d+', str(answer))
        if nums:
            for num in nums:
                if int(num) % 2020 == S_mod:
                    return True
        return False

