def verify(answer):
    import re
    from math import comb, isclose
    from scipy.optimize import brentq
    import numpy as np

    # The known answer is x_k = C(n,k) / 2^(n-1) * ... let's check
    # Actually let's verify the claimed formula numerically

    def get_xk_sequence(n, c):
        x = [0.0] * (n + 2)
        x[0] = 0.0
        x[1] = 1.0
        for k in range(n):
            x[k+2] = (c * x[k+1] - (n - k) * x[k]) / (k + 1)
        return x

    def find_c(n):
        def f(c):
            return get_xk_sequence(n, c)[n+1]
        # find largest root
        from numpy.polynomial import polynomial as P
        # search in a range
        roots = []
        for lo, hi in [(-20, 20)]:
            try:
                # sample
                cs = np.linspace(lo, hi, 10000)
                vals = [f(c) for c in cs]
                for i in range(len(vals)-1):
                    if vals[i]*vals[i+1] < 0:
                        r = brentq(f, cs[i], cs[i+1])
                        roots.append(r)
            except:
                pass
        if not roots:
            return None
        return max(roots)

    # The answer should be x_k = C(n,k) / 2^(n-1)
    # Let's check the formula from the answer string
    # Expected: x_k = C(n,k)/2^(n-1)

    for n in [2, 3, 4, 5]:
        c = find_c(n)
        if c is None:
            continue
        xs = get_xk_sequence(n, c)
        for k in range(1, n+1):
            expected = comb(n, k) / (2**(n-1))
            if not isclose(xs[k], expected, rel_tol=1e-4, abs_tol=1e-6):
                return False

    # Check that the answer string mentions C(n,k)/2^(n-1) or binomial(n,k)/2^(n-1)
    ans = answer.lower().replace(" ", "")
    patterns = ["binom", "c(n,k)", "\\binom", "2^{n-1}", "2^(n-1)", "combinat"]
    return any(p in ans for p in patterns)
